parameters.prompt:
=You are a precise extraction system. Extract structured information from this meeting.

TRANSCRIPT:
{{ $json.transcript }}

PARTICIPANTS:
{{ $json.participants }}

HUMAN NOTES (if any):
{{ $json.human_notes }}

Extract the following and respond ONLY with valid JSON:

{
  "summary": "2-3 sentence meeting summary",
  "action_items": [
    {"task": "description", "owner": "name or unknown", "confidence": 0.0-1.0}
  ],
  "crm_updates": {
    "stage_change": "new stage or null",
    "next_step": "description or null",
    "confidence": 0.0-1.0
  },
  "follow_ups": [
    {"type": "email|call|task", "recipient": "name", "intent": "description", "is_external": true|false, "confidence": 0.0-1.0}
  ],
  "overall_confidence": 0.0-1.0,
  "flags": ["any concerns or ambiguities"]
}

Rules:
- Set confidence to 0 if information is unclear
- Flag any conflicting information
- Mark is_external=true for customer/prospect emails
- Use "unknown" for unclear owners

parameters.jsCode:
// Parse and validate LLM output
const executionId = $input.first().json.execution_id;
const rawResponse = $input.first().json.response;

let extracted;
try {
  // Try to parse JSON from response
  const jsonMatch = rawResponse.match(/\{[\s\S]*\}/);
  if (!jsonMatch) {
    throw new Error('No JSON found in response');
  }
  extracted = JSON.parse(jsonMatch[0]);
} catch (error) {
  return [{
    json: {
      execution_id: executionId,
      status: 'extraction_failed',
      error: error.message,
      raw_response: rawResponse,
      decision_log: {
        timestamp: new Date().toISOString(),
        stage: 'llm_extraction',
        result: 'failed',
        reason: 'JSON parse error'
      }
    }
  }];
}

// Validate confidence thresholds
const MIN_CONFIDENCE = 0.7;
const validationResult = {
  execution_id: executionId,
  extracted_data: extracted,
  validation: {
    overall_confidence_pass: extracted.overall_confidence >= MIN_CONFIDENCE,
    crm_update_safe: extracted.crm_updates?.confidence >= MIN_CONFIDENCE,
    external_emails_detected: extracted.follow_ups?.some(f => f.is_external && f.confidence >= MIN_CONFIDENCE) || false,
    flags: extracted.flags || [],
    requires_human_review: false
  },
  decision_log: {
    timestamp: new Date().toISOString(),
    stage: 'extraction_validation',
    confidence_scores: {
      overall: extracted.overall_confidence,
      crm: extracted.crm_updates?.confidence || 0,
      actions: extracted.action_items?.map(a => a.confidence) || []
    }
  }
};

// Determine if human review needed
if (!validationResult.validation.overall_confidence_pass) {
  validationResult.validation.requires_human_review = true;
  validationResult.validation.review_reason = 'Low overall confidence';
} else if (validationResult.validation.external_emails_detected) {
  validationResult.validation.requires_human_review = true;
  validationResult.validation.review_reason = 'External email detected - requires approval';
} else if (!validationResult.validation.crm_update_safe && extracted.crm_updates?.stage_change) {
  validationResult.validation.requires_human_review = true;
  validationResult.validation.review_reason = 'CRM stage change with low confidence';
} else if (extracted.flags?.length > 0) {
  validationResult.validation.requires_human_review = true;
  validationResult.validation.review_reason = 'LLM flagged concerns: ' + extracted.flags.join(', ');
}

return [{ json: validationResult }];

additionalFields.notes:
=Execution ID: {{ $json.execution_id }}

REVIEW REASON: {{ $json.validation.review_reason }}

--- EXTRACTED DATA ---
Summary: {{ $json.extracted_data.summary }}

CRM Updates:
{{ JSON.stringify($json.extracted_data.crm_updates, null, 2) }}

Follow-ups:
{{ JSON.stringify($json.extracted_data.follow_ups, null, 2) }}

Action Items:
{{ JSON.stringify($json.extracted_data.action_items, null, 2) }}

Flags: {{ $json.extracted_data.flags?.join(', ') || 'None' }}

--- APPROVAL ACTIONS ---
To approve: Reply to this task with 'APPROVED'
To reject: Reply with 'REJECTED'

Auto-expires in 24 hours.

parameters.jsCode:
// Auto-approved - execute safe internal actions only
const data = $input.first().json;
const executionId = data.execution_id;
const extracted = data.extracted_data;

// Prepare safe actions (internal only, no external emails, no risky CRM changes)
const safeActions = [];

// Add internal action items
if (extracted.action_items?.length > 0) {
  extracted.action_items.forEach((item, idx) => {
    if (item.confidence >= 0.7) {
      safeActions.push({
        type: 'create_task',
        data: {
          title: item.task,
          owner: item.owner,
          source_meeting: executionId
        }
      });
    }
  });
}

// Add safe CRM update (next step only, no stage change)
if (extracted.crm_updates?.next_step && extracted.crm_updates.confidence >= 0.7) {
  safeActions.push({
    type: 'update_crm_note',
    data: {
      deal_id: data.deal_id,
      note: `Meeting Summary: ${extracted.summary}\n\nNext Step: ${extracted.crm_updates.next_step}`,
      source_meeting: executionId
    }
  });
}

return [{
  json: {
    execution_id: executionId,
    status: 'auto_approved',
    actions: safeActions,
    decision_log: {
      timestamp: new Date().toISOString(),
      stage: 'execution_approval',
      result: 'auto_approved',
      reason: 'All checks passed, only safe actions'
    }
  }
}];
